import { useState } from "react";
import { addVehicle } from "../../api/vehicleApi";

function AddVehicle() {
  const [vehicle, setVehicle] = useState({
    brand: "",
    type: "", 
    year: "",
    price: "",
    status: "available",
  });

  const vehicleTypes = ["SUV", "Sedan", "Hatchback", "Truck", "Van", "Coupe"];

  const handleChange = (e) => {
    const { name, value } = e.target;
    setVehicle({ ...vehicle, [name]: value });
  };

  const submit = async (e) => {
    e.preventDefault();
    const currentYear = new Date().getFullYear();
    if (vehicle.year > currentYear) {
      alert(`Year cannot be in the future (max ${currentYear})`);
      return;
    }

    try {
      await addVehicle(vehicle);
      alert("Vehicle added successfully");
      setVehicle({
        brand: "",
        type: "",
        year: "",
        price: "",
        status: "available",
      });
    } catch (err) {
      alert(err.response?.data?.message || "Error adding vehicle");
    }
  };

  return (
    <form onSubmit={submit}>
      <h2>Add Vehicle</h2>

      <input
        name="brand"
        placeholder="Brand"
        value={vehicle.brand}
        onChange={handleChange}
      />

      {/* Vehicle Type Dropdown */}
      <select name="type" value={vehicle.type} onChange={handleChange}>
        <option value="">Select Vehicle Type</option>
        {vehicleTypes.map((t) => (
          <option key={t} value={t}>
            {t}
          </option>
        ))}
      </select>

      <input
        name="year"
        type="number"
        placeholder="Year"
        value={vehicle.year}
        onChange={handleChange}
      />

      <input
        name="price"
        type="number"
        placeholder="Price"
        value={vehicle.price}
        onChange={handleChange}
      />

      <select name="status" value={vehicle.status} onChange={handleChange}>
        <option value="available">Available</option>
        <option value="reserved">Reserved</option>
        <option value="sold">Sold</option>
      </select>

      <button type="submit">Save</button>
    </form>
  );
}

export default AddVehicle;
